// Facebook Lead Ads delivers leads as:
// { object: 'page', entry: [{ changes: [{ field: 'leadgen', value: { leadgen_id, page_id, form_id, adgroup_id, ad_id, created_time } }] }] }
// You then need a second API call to /{leadgen_id}?fields=field_data,created_time using
// a Page access token to fetch the actual fields. For simplicity this template assumes
// the user has either:
//   - already enriched the payload upstream (field_data present), OR
//   - is in test mode where Facebook posts the field_data inline.
// Adjust as needed for your token flow.
const body = $input.first().json.body || {};
const out = [];
for (const entry of (body.entry || [])) {
  for (const change of (entry.changes || [])) {
    const v = change.value || {};
    const fields = v.field_data || v.fields || [];
    const flat = {};
    for (const f of fields) {
      const k = String(f.name || '').toLowerCase().replace(/[^a-z0-9]+/g, '_');
      const val = Array.isArray(f.values) ? f.values[0] : f.value;
      flat[k] = val ?? '';
    }
    const phone = (flat.phone_number || flat.phone || flat.mobile || '').toString().trim();
    const first = (flat.first_name || flat.full_name || '').toString().trim();
    const last  = (flat.last_name || '').toString().trim();
    const email = (flat.email || '').toString().trim();
    out.push({
      json: {
        e164: phone,
        first_name: first,
        last_name: last,
        name: [first, last].filter(Boolean).join(' ') || flat.full_name || '',
        email,
        lead_id: v.leadgen_id || '',
        created_time: v.created_time || new Date().toISOString(),
        page_id: v.page_id || '',
        form_id: v.form_id || '',
        ad_id: v.ad_id || '',
        raw: flat,
      },
    });
  }
}
if (out.length === 0) {
  out.push({ json: { _empty: true } });
}
return out;
